-- SMALLFILE 테이블스페이스에 데이터 파일 추가
ALTER TABLESPACE app_data
  ADD DATAFILE '/u01/app/oracle/oradata/orcl26ai/app_data02.dbf' SIZE 2G
  AUTOEXTEND ON NEXT 200M MAXSIZE 10G;

-- 데이터 파일 크기 수동 변경 (확장)
ALTER DATABASE DATAFILE '/u01/app/oracle/oradata/orcl26ai/app_data01.dbf'
  RESIZE 5G;

-- 데이터 파일 크기 수동 변경 (축소 — 사용 중인 공간 이하로 불가)
ALTER DATABASE DATAFILE '/u01/app/oracle/oradata/orcl26ai/app_data01.dbf'
  RESIZE 500M;

-- BIGFILE 테이블스페이스 생성
CREATE BIGFILE TABLESPACE warehouse_data
  DATAFILE '/u01/app/oracle/oradata/orcl26ai/warehouse01.dbf' SIZE 100G
  AUTOEXTEND ON NEXT 1G MAXSIZE 5T;

-- BIGFILE 테이블스페이스 레벨 크기 변경
ALTER TABLESPACE warehouse_data RESIZE 200G;

-- BIGFILE 테이블스페이스 레벨 자동 확장 변경
ALTER TABLESPACE warehouse_data
  AUTOEXTEND ON NEXT 2G MAXSIZE 10T;

-- OMF 파일 생성 경로 설정
ALTER SYSTEM SET DB_CREATE_FILE_DEST = '+DATA' SCOPE=BOTH;

-- OMF 환경에서 BIGFILE 테이블스페이스 생성 (파일 경로 자동)
CREATE BIGFILE TABLESPACE big_archive
  DATAFILE SIZE 50G
  AUTOEXTEND ON NEXT 1G MAXSIZE UNLIMITED;

-- BIGFILE 임시 테이블스페이스 생성 (OMF)
CREATE BIGFILE TEMPORARY TABLESPACE big_temp
  TEMPFILE SIZE 10G
  AUTOEXTEND ON NEXT 1G MAXSIZE 100G;

-- 데이터베이스 기본 설정 조회
SELECT PROPERTY_NAME, PROPERTY_VALUE
FROM DATABASE_PROPERTIES
WHERE PROPERTY_NAME IN (
  'DEFAULT_PERMANENT_TABLESPACE',
  'DEFAULT_TEMP_TABLESPACE',
  'DEFAULT_TBS_TYPE'
)
ORDER BY PROPERTY_NAME;

-- 기본 영구 테이블스페이스 변경
ALTER DATABASE DEFAULT TABLESPACE users;

-- 기본 임시 테이블스페이스 변경
ALTER DATABASE DEFAULT TEMPORARY TABLESPACE temp;

-- 기본 테이블스페이스 타입을 BIGFILE로 변경
ALTER DATABASE SET DEFAULT BIGFILE TABLESPACE;
